/**
 * OKKI 快速同步 v4 — 登录 OKKI → 加载 onetalk → 抓取 TM 会话数据
 *
 * 使用：
 * 1. 关闭 Chrome
 * 2. node scripts/quick_sync.js
 * 3. 在浏览器中手动登录 OKKI
 * 4. 登录成功后自动跳转 onetalk → 抓取 → 保存 → 退出
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const PROFILE_PATH = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

const captured = [];
const wsMessages = [];

async function main() {
  console.log('[QuickSync v4] 启动 Chrome (Profile 4)...');

  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
    channel: 'chrome',
    headless: false,
    viewport: { width: 1440, height: 900 },
  });

  const page = await browser.newPage();

  // ---- HTTP 拦截 ----
  page.on('response', async (response) => {
    const url = response.url();
    if (!url.includes('xiaoman') && !url.includes('alibaba.com') && !url.includes('alicdn.com')) return;
    try {
      const ct = response.headers()['content-type'] || '';
      if (!ct.includes('json')) return;
      const body = await response.json().catch(() => null);
      if (!body) return;
      captured.push({ time: new Date().toISOString(), url, status: response.status(), data: body });
      const short = url.split('?')[0];
      const list = body.data?.list || body.data?.records || body.list;
      const count = Array.isArray(list) ? list.length : (body.data?.total || body.total || '');
      if (count || url.includes('chat') || url.includes('message') || url.includes('contact')) {
        console.log(`  [HTTP] ${response.status()} | ${count}条 | ${short.slice(-80)}`);
      }
    } catch (e) {}
  });

  // ---- WebSocket 拦截 ----
  page.on('websocket', (ws) => {
    const wsUrl = ws.url();
    console.log(`  [WS] 连接: ${wsUrl.slice(0, 100)}`);
    ws.on('framereceived', (frame) => {
      try {
        const text = frame.payload.toString('utf-8');
        if (text.length < 20) return;
        const obj = JSON.parse(text);
        wsMessages.push({ time: new Date().toISOString(), url: wsUrl, data: obj });

        if (obj.body?.userMessageModels) {
          const msgs = obj.body.userMessageModels;
          console.log(`  [WS←] 消息列表: ${msgs.length}条 | cursor:${obj.body.nextCursor || 'none'}`);
        } else if (obj.lwp || obj.code !== undefined) {
          const preview = text.slice(0, 150);
          console.log(`  [WS←] ${preview}`);
        }
      } catch (e) {}
    });
  });

  // ==== Step 1: 登录 OKKI ====
  console.log('[Step 1] 导航到 OKKI...');
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 });

  console.log('');
  console.log('========================================');
  console.log('  请在浏览器中手动登录 OKKI');
  console.log('  登录成功后自动继续...');
  console.log('========================================');
  console.log('');

  const startTime = Date.now();
  const maxWait = 5 * 60 * 1000;
  while (Date.now() - startTime < maxWait) {
    const currentUrl = page.url();
    if (!currentUrl.includes('login.xiaoman.cn') && currentUrl.includes('crm.xiaoman.cn')) {
      console.log('[Step 1] 登录成功！');
      break;
    }
    await page.waitForTimeout(2000);
  }

  if (page.url().includes('login.xiaoman.cn')) {
    console.log('[Step 1] 超时。退出。');
    await browser.close();
    process.exit(1);
  }

  // ==== Step 2: 加载 onetalk TM ====
  console.log('[Step 2] 加载 onetalk TM 页面...');
  await page.goto(
    'https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman',
    { waitUntil: 'domcontentloaded', timeout: 20000 }
  ).catch(() => console.log('  (onetalk 加载超时，继续...)'));
  await page.waitForTimeout(3000);

  console.log(`[Step 2] onetalk URL: ${page.url()}`);

  // ==== Step 3: 等待 WebSocket 数据 ====
  console.log('[Step 3] 等待 WebSocket 连接和数据 (15秒)...');
  await page.waitForTimeout(15000);

  // ==== Step 4: DOM 提取 ====
  const domData = await page.evaluate(() => {
    const result = { title: document.title, url: location.href, bodyClasses: document.body.className };

    // 尝试提取会话列表项
    const allText = document.body.innerText?.slice(0, 2000);
    result.bodyPreview = allText;

    // 找列表元素
    const selectors = [
      '[class*="contact"]', '[class*="session"]', '[class*="conversation"]',
      '[class*="chat"]', '[class*="list"] li', 'li', '[role="listitem"]',
    ];
    for (const sel of selectors) {
      const els = document.querySelectorAll(sel);
      if (els.length > 5) {
        result.listSelector = sel;
        result.listCount = els.length;
        result.sampleTexts = [];
        for (let i = 0; i < Math.min(els.length, 5); i++) {
          result.sampleTexts.push(els[i].textContent?.slice(0, 150));
        }
        break;
      }
    }
    return result;
  });

  console.log(`[Step 4] DOM: ${domData.listSelector || '无列表'} (${domData.listCount || 0}个)`);

  // ==== Step 5: 保存 ====
  const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const filepath = path.join(OUTPUT_DIR, `quicksync_${ts}.json`);

  fs.writeFileSync(filepath, JSON.stringify({
    syncedAt: new Date().toISOString(),
    step2Url: page.url(),
    domData,
    httpCount: captured.length,
    wsCount: wsMessages.length,
    httpResponses: captured,
    wsMessages,
  }, null, 2));

  console.log(`[Step 5] 完成。HTTP:${captured.length} WS:${wsMessages.length} → ${path.basename(filepath)}`);
  await browser.close();
}

main().catch(err => {
  console.error('[QuickSync v4] 错误:', err.message);
  process.exit(1);
});

