238	  // 展平结果
239	  const convList = convData.list;
240	  const totalCount = convData.count;
241	
242	  log(`提取到 ${totalCount} 个会话`);
243	
244	  // ---- Step 6: 保存最新元数据 ----
245	  const latestMeta = {
246	    exportedAt: new Date().toISOString(),
247	    total: totalCount,
248	    conversations: convList,
249	  };
250	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
251	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
252	  log(`元数据已保存: tm_conversations_latest.json (${totalCount} 会话)`);
253	
254	  // ---- Step 7: Diff 找出变化的会话 ----
255	  log('对比上次数据...');
256	  let oldMeta = null;
257	  const oldPath = path.join(DATA_DIR, 'tm_conversations_full.json');
258	  if (fs.existsSync(oldPath)) {
259	    oldMeta = JSON.parse(fs.readFileSync(oldPath, 'utf-8'));
260	  }
261	
262	  const changed = [];
263	  const oldMap = new Map();
264	  if (oldMeta?.conversations) {
265	    for (const c of oldMeta.conversations) {
266	      oldMap.set(c.cid, c);
267	    }
268	  }
269	
270	  for (const c of convList) {
271	    const old = oldMap.get(c.cid);
272	    if (!old) {
273	      // 新会话
274	      changed.push({ cid: c.cid, name: c.name, reason: '新会话', oldLmId: null, newLmId: c.latestMessage?.messageId });
275	      continue;
276	    }
277	    const oldLmId = old.latestMessage?.messageId;
278	    const newLmId = c.latestMessage?.messageId;
279	    const oldLct = old.lastContactTime || 0;
280	    const newLct = c.lastContactTime || 0;
281	
282	    if (oldLmId !== newLmId || newLct > oldLct) {
283	      const reason = oldLmId !== newLmId ? '消息更新' : '时间更新';
284	      changed.push({ cid: c.cid, name: c.name, reason, oldLmId, newLmId });
285	    }
286	  }
287	
288	  log(`变化会话: ${changed.length} 个`);
289	  if (changed.length > 0) {
290	    for (const ch of changed.slice(0, 15)) {
291	      log(`  ${ch.reason}: ${ch.name}`);
292	    }
293	    if (changed.length > 15) log(`  ... 共 ${changed.length} 个`);
294	  }
295	
296	  // ---- Step 8: 增量拉取聊天历史 ----
297	  if (changed.length === 0) {
298	    log('无变化，无需拉取聊天历史。同步完成。');
299	    printSummary(convList, changed);
300	    await browser.close();
301	    return;
302	  }
303	
304	  log('');
305	  log(`开始增量拉取 ${changed.length} 个会话的聊天历史...`);
306	
307	  // 获取 CDP session
308	  let cdpClient;
309	  let iframeSessionId;
310	
311	  if (!useCdp) {
312	    // Playwright 启动模式: 需要通过 CDP 访问 iframe
313	    cdpClient = await page.context().newCDPSession(page);
314	    const targets = await cdpClient.send('Target.getTargets');
315	    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
316	    if (ot) {
317	      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
318	      iframeSessionId = attached.sessionId;
319	      log(`CDP attached to onetalk iframe: ${ot.url.slice(0, 80)}`);
320	    } else {
321	      log('警告: 未找到 onetalk iframe target，尝试用 page.frames() 方式...');
322	    }
323	  } else {
324	    // CDP 连接模式: page 已经是 CDP 连接的
325	    cdpClient = await page.context().newCDPSession(page);
326	    const targets = await cdpClient.send('Target.getTargets');
327	    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
328	    if (!ot) {
329	      // 检查 page 本身是否是 onetalk
330	      if (page.url().includes('onetalk')) {
331	        iframeSessionId = undefined; // page 本身就是 onetalk
332	        log('当前页面就是 onetalk');
333	      } else {
334	        log('警告: 未找到 onetalk target');
335	      }
336	    } else {
337	      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
338	      iframeSessionId = attached.sessionId;
339	      log(`CDP attached to onetalk iframe`);
340	    }
341	  }
342	
343	  // 安装 LWP 收发器
344	  if (iframeSessionId || page.url().includes('onetalk')) {
345	    log('安装 LWP 收发器...');
346	    await installLwp(cdpClient, iframeSessionId);
347	    await sleep(3000);
348	
349	    // 确认 WS 已捕获
350	    const wsState = await evalInIframe(cdpClient, iframeSessionId, 10,
351	      `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
352	    );
353	    log(`WS 状态: ${JSON.stringify(wsState)}`);
354	
355	    if (!wsState?.ws) {
356	      log('等待 WebSocket 连接...');
357	      await sleep(15000);
358	      const wsState2 = await evalInIframe(cdpClient, iframeSessionId, 11,
359	        `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
360	      );
361	      log(`WS 状态(重试): ${JSON.stringify(wsState2)}`);
362	    }
363	
364	    // 拉取消息
365	    let pulled = 0;
366	    let errors = 0;
367	    let totalNewMsgs = 0;
368	    let msgIdCounter = 100;
369	
370	    for (let i = 0; i < changed.length; i++) {
371	      const conv = changed[i];
372	      try {
373	        const allMessages = [];
374	        let cursor = 9007199254740991;
375	        let pageNum = 0;
376	
377	        while (pageNum < MAX_PAGES) {
378	          const msgId = msgIdCounter++;
379	          const raw = await evalInIframe(cdpClient, iframeSessionId, msgId,
380	            `(async function() {
381	              try {
382	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${conv.cid}', false, ${cursor}, ${MSG_COUNT}, false]);
383	                return JSON.stringify(result);
384	              } catch(e) {
385	                return JSON.stringify({ __error: e.message });
386	              }
387	            })()`,
388	            true
389	          );
390	
391	          await sleep(1500);
392	
393	          if (!raw || raw.__error) {
394	            if (raw?.__error === 'timeout') { log(`  [${conv.name}] LWP超时`); }
395	            break;
396	          }
397	
398	          let response;
399	          try { response = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { break; }
400	          if (response.code !== 200) break;
401	
402	          const body = response.body;
403	          if (!body?.userMessageModels || body.userMessageModels.length === 0) break;
404	
405	          allMessages.push(...body.userMessageModels);
406	
407	          if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
408	          cursor = body.nextCursor;
409	          pageNum++;
410	        }
411	
412	        // 保存
413	        const safeName = sanitizeFilename(conv.cid);
414	        const output = {
415	          cid: conv.cid,
416	          name: conv.name,
417	          fetchedAt: new Date().toISOString(),
418	          totalMessages: allMessages.length,
419	          messages: allMessages,
420	        };
421	        fs.writeFileSync(path.join(CHAT_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
422	        pulled++;
423	        totalNewMsgs += allMessages.length;
424	        if (allMessages.length > 0) {
425	          log(`  [${i+1}/${changed.length}] ${conv.name}: ${allMessages.length} 条消息`);
426	        }
427	      } catch (e) {
428	        errors++;
429	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
430	      }
431	    }
432	
433	    log(`拉取完成: ${pulled} 个会话, ${totalNewMsgs} 条消息, ${errors} 个错误`);
434	  } else {
435	    log('跳过 LWP 拉取（无 CDP/iframe 访问）');
436	    log('已保存元数据差异。在新对话中可通过 STATE.md 了解哪些客户需要深抓。');
437	  }
438	
439	  // ---- Step 9: 输出摘要 ----
440	  printSummary(convList, changed);
441	  await browser.close();
442	  log('同步完成。');
443	}
444	
445	// ===================== LWP 工具 =====================
446	
447	async function installLwp(cdpClient, iframeSessionId) {
448	  const expr = `
449	    (function() {
450	      var _send = WebSocket.prototype.send;
451	      var _ae = WebSocket.prototype.addEventListener;
452	
453	      window.__lwpPending = {};
454	      window.__lwpSeq = 0;
455	
456	      WebSocket.prototype.send = function(data) {
457	        if (!window.__lwpWs && this.readyState === 1) {
458	          window.__lwpWs = this;
459	          _ae.call(this, 'message', function(event) {
460	            try {
461	              var raw = typeof event.data === 'string' ? event.data : '';
462	              if (raw.indexOf('"code"') < 0) return;
463	              var parsed = JSON.parse(raw);
464	              var mid = parsed.headers && parsed.headers.mid;
465	              if (mid && window.__lwpPending[mid]) {
466	                var p = window.__lwpPending[mid];
467	                delete window.__lwpPending[mid];
468	                p.resolve(parsed);
469	              }
470	            } catch(e) {}
471	          });
472	          console.log('[LWP] WS captured: ' + this.url);
473	        }
474	        return _send.call(this, data);
475	      };
476	
477	      window.__lwpRequest = function(lwpPath, body) {
478	        return new Promise(function(resolve, reject) {
479	          var ws = window.__lwpWs;
480	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
481	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
482	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
483	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
484	          ws.send(req);
485	          setTimeout(function() {
486	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
487	          }, 30000);
488	        });
489	      };
490	
491	      return JSON.stringify({ installed: true });
492	    })()
493	  `;
494	
495	  return sendToTarget(cdpClient, iframeSessionId, 3, expr);
496	}
497	
498	async function evalInIframe(cdpClient, iframeSessionId, id, expression, awaitPromise) {
499	  const raw = await sendToTarget(cdpClient, iframeSessionId, id, expression, awaitPromise);
500	  if (!raw) return raw;
501	  try { return JSON.parse(raw); } catch (e) { return raw; }
502	}
503	
504	async function sendToTarget(cdpClient, sessionId, id, expression, awaitPromise) {
505	  return new Promise((resolve) => {
506	    const timeout = setTimeout(() => resolve(null), 35000);
507	
508	    const handler = (msg) => {
509	      if (sessionId && msg.sessionId !== sessionId) return;
510	      try {
511	        const m = JSON.parse(msg.message);
512	        if (m.id === id) {
513	          clearTimeout(timeout);
514	          cdpClient.off('Target.receivedMessageFromTarget', handler);
515	          if (m.result?.result?.value !== null && m.result?.result?.value !== undefined) {
516	            resolve(m.result.result.value);
517	          } else if (m.result) {
518	            resolve(m.result);
519	          } else {
520	            resolve(null);
521	          }
522	        }
523	      } catch (e) { clearTimeout(timeout); resolve(null); }
524	    };
525	
526	    cdpClient.on('Target.receivedMessageFromTarget', handler);
527	
528	    cdpClient.send('Target.sendMessageToTarget', {
529	      sessionId: sessionId || cdpClient._sessionId,
530	      message: JSON.stringify({
531	        id,
532	        method: 'Runtime.evaluate',
533	        params: { expression, awaitPromise: !!awaitPromise, returnByValue: true }
534	      })
535	    }).catch(() => { clearTimeout(timeout); resolve(null); });
536	  });
537	}
538	
539	function printSummary(convData, changed) {
540	  // 统计（基于原始消息数据，不依赖 latestMessage）
541	  const now = Date.now();
542	  const last24h = convData.filter(c => (c.lastContactTime || 0) > now - 86400000).length;
543	
544	  // 从 chat_history 文件统计客户回复（不是从 latestMessage）
545	  let totalCustomerMsgs = 0;
546	  let totalOurMsgs = 0;
547	  let customersReplied = new Set();
548	  const CUTOFF = now - 7 * 86400000;
549	
550	  const chatDir = path.join(DATA_DIR, 'chat_history');
551	  if (fs.existsSync(chatDir)) {
552	    const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json') && f !== '_summary.json');
553	    for (const file of files) {
554	      try {
555	        const data = JSON.parse(fs.readFileSync(path.join(chatDir, file), 'utf-8'));
556	        for (const msg of (data.messages || [])) {
557	          const ts = msg.message?.createAt || 0;
558	          if (ts < CUTOFF) continue;
559	          const sender = msg.message?.sender?.uid || '';
560	          const content = msg.message?.content?.text?.content || '';
561	          if (!content) continue;
562	          if (sender === '2500000853693@icbu') {
563	            totalOurMsgs++;
564	          } else {
565	            totalCustomerMsgs++;
566	            customersReplied.add(data.cid || file);
567	          }
568	        }
569	      } catch (e) {}
570	    }
571	  }
572	
573	  log('');
574	  log('========== 同步摘要 ==========');
575	  log(`总会话: ${convData.length}`);
576	  log(`变化会话: ${changed.length}`);
577	  log(`24h内有 activity: ${last24h}`);
578	  log('');
579	  log(`近7天消息 (来自 chat_history 实测):`);
580	  log(`  客户回复: ${totalCustomerMsgs} 条 / ${customersReplied.size} 人`);
581	  log(`  我方发送: ${totalOurMsgs} 条`);
582	  log(`数据已保存到 data/ 目录`);
583	  log('==============================');
584	}
585	
586	// ===================== 启动 =====================
587	
588	main().catch(err => {
589	  log(`致命错误: ${err.message}`);
590	  console.error(err);
591	  process.exit(1);
592	});
