            container = el;
            break;
          }
        }
      }
      if (!container) return { done: true, count: (window.__conversationListFullData__ || []).length };

      const before = (window.__conversationListFullData__ || []).length;
      // 滚动到底部
      container.scrollTop = container.scrollHeight;
      return { done: false, before, scrollHeight: container.scrollHeight, clientHeight: container.clientHeight };
    });

    if (result.done) { console.log('  滚动完成，容器已到底'); break; }

    await sleep(1500);
    const newCount = await otFrame.evaluate(() => (window.__conversationListFullData__ || []).length);
    console.log('  第' + (round+1) + '轮: ' + result.before + ' → ' + newCount);

