  const targets = ['Abigail', 'Mutuku', 'Noslen', 'Gonzalez', 'ivy', 'quarcoo', 'Elton', 'daNadia', 'Samia', 'Guenad', 'Nadia'];
  for (const t of targets) {
    const matches = finalData.names.filter(n => n && n.toLowerCase().includes(t.toLowerCase()));
    if (matches.length > 0) {
      console.log('  FOUND \"' + t + '\":', matches);
    }
  }

  // 保存完整数据
  const fullData = await otFrame.evaluate(() => {
    const convs = window.__conversationListFullData__ || [];
    return convs.map(c => ({
      cid: c.cid, name: c.name, loginId: c.loginId, aliId: c.aliId,
      accountId: c.accountId, companyName: c.companyName,
      country: c.country, level: c.level,
      serviceType: c.serviceType, conversationType: c.conversationType,
      unreadCount: c.unreadCount,
      lastContactTime: c.lastContactTime,
      lastContactTimeLong: c.lastContactTimeLong,
      complianceCountryCode: c.complianceCountryCode,
      latestMessage: c.latestMessage ? {
        content: c.latestMessage.content,
        messageType: c.latestMessage.messageType,
        messageId: c.latestMessage.messageId,
        gmtChat: c.latestMessage.gmtChat,
        contactRead: c.latestMessage.contactRead,
      } : null,
    }));
  });

  const outPath = path.join(DATA_DIR, 'tm_conversations_full_scrolled.json');
  fs.writeFileSync(outPath, JSON.stringify({ exportedAt: new Date().toISOString(), total: finalData.count, conversations: fullData }, null, 2));
  console.log('已保存:', outPath, '(' + finalData.count + '会话)');

  // 也更新 latest
  fs.writeFileSync(path.join(DATA_DIR, 'tm_conversations_latest.json'), JSON.stringify({ exportedAt: new Date().toISOString(), total: finalData.count, conversations: fullData }, null, 2));

  await browser.close();
  console.log('完成');
}
main().catch(e => { console.error(e.message); process.exit(1); });
