/**
 * 定向拉取指定客户的聊天历史
 */
const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const DATA_DIR = path.join(__dirname, '..', 'data');
const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
const MSG_COUNT = 50;
const MAX_PAGES = 10;

const TARGETS = [
  { name: 'Abigail Mutuku', cid: '133341149734-2500000853693#11011@icbu' },
  { name: 'Noslen Gonzalez', cid: '1507604597007-2500000853693#11011@icbu' },
  { name: 'ivy quarcoo', cid: '17301762067-2500000853693#11011@icbu' },
  { name: 'Elton daNadia', cid: '1507597605831-2500000853693#11011@icbu' },
  { name: 'Samia Guenad', cid: '1507567810538-2500000853693#11011@icbu' },
  { name: 'RebeccaNytanieAude SEHE', cid: null },
];

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }

async function main() {
  log('启动 Chrome...');
  const browser = await chromium.launchPersistentContext(PROFILE, {
    channel: 'chrome',
    headless: false,
    viewport: { width: 1440, height: 900 },
  });

  const page = await browser.newPage();
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});

  // 登录检测
  if (page.url().includes('login')) {
    log('请在浏览器中登录 OKKI...');
    const start = Date.now();
    while (Date.now() - start < 5 * 60 * 1000) {
      if (!page.url().includes('login')) { log('登录成功!'); break; }
      await sleep(2000);
    }
  }

  await sleep(3000);

  // 等onetalk
  let otFrame = null;
  for (let i = 0; i < 30; i++) {
    otFrame = page.frames().find(f => f.url().startsWith('https://onetalk.alibaba.com/'));
    if (otFrame) break;
    await sleep(2000);
  }
  if (!otFrame) { log('onetalk未找到'); await browser.close(); return; }
  log('onetalk已加载');

  // 如果Rebecca没找到cid，先搜索
  const rebecca = TARGETS.find(t => t.name === 'RebeccaNytanieAude SEHE');
  if (rebecca && !rebecca.cid) {
    rebecca.cid = await otFrame.evaluate((name) => {
      const d = window.__conversationListFullData__ || [];
      const c = d.find(x => x.name === name);
      return c ? c.cid : null;
    }, rebecca.name);
    log('Rebecca cid: ' + (rebecca.cid || 'NOT FOUND'));
  }

  // CDP连接
