    silent: [],            // 沉默/低活跃
  };

  const UID_ME = '2500000853693@icbu';

  for (const c of fullMeta) {
    const age = (now - (c.lastContactTime || 0)) / DAY;
    const isUnread = c.unreadCount > 0;

    // 尝试读 chat_history
    const sanitized = c.cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
    const chatFile = path.join(CHAT_DIR, sanitized + '.json');
    let messages = [];
    if (fs.existsSync(chatFile)) {
      try {
        messages = JSON.parse(fs.readFileSync(chatFile, 'utf-8')).messages || [];
      } catch (e) {}
    }

    // 找最后一条客户消息 和 最后一条人工回复
    let lastCustMsg = null;
    let lastHumanReply = null;
    let lastSysReply = null;

    for (let i = messages.length - 1; i >= 0; i--) {
      const m = messages[i];
      const content = m.message?.content?.text?.content || '';
      const senderUid = m.message?.sender?.uid || '';
      const isFromMe = senderUid === UID_ME;

      if (isFromMe) {
        if (!lastHumanReply && !isSystemMessage(content) && content.trim().length > 5) {
          // 排除空消息和纯图片消息
          lastHumanReply = { content, time: m.message?.createAt || 0 };
        }
        if (!lastSysReply && isSystemMessage(content)) {
          lastSysReply = { content, time: m.message?.createAt || 0 };
        }
      } else {
        if (!lastCustMsg) {
          lastCustMsg = { content, time: m.message?.createAt || 0 };
          break; // 找到最近客户消息即可
        }
      }
    }

    // 如果 chat_history 中没有，用 latestMessage 推断
    if (!lastCustMsg && !lastHumanReply) {
      const lm = c.latestMessage;
      if (lm) {
        if (lm.messageType === 'received') {
          lastCustMsg = { content: lm.content, time: c.lastContactTime || 0 };
        } else if (!isSystemMessage(lm.content || '')) {
          lastHumanReply = { content: lm.content, time: c.lastContactTime || 0 };
        } else {
          lastSysReply = { content: lm.content, time: c.lastContactTime || 0 };
        }
      }
    }

    const custTime = lastCustMsg?.time || 0;
    const replyTime = lastHumanReply?.time || 0;
    const custAfterReply = custTime > replyTime; // 客户在我们回复后又发了消息

    let status, detail;

    if (isUnread && custAfterReply) {
      status = 'unread_no_reply';
      detail = '客户新消息未被回复';
    } else if (isUnread && !custAfterReply) {
      status = 'unread_replied';
      detail = '已回复但客户有更早的未读消息';
    } else if (!isUnread && custTime > replyTime && age <= 7) {
      status = 'read_no_reply';
      detail = '已读但客户最新消息未回复';
    } else if (!isUnread && replyTime >= custTime && age <= 7) {
      status = 'read_replied';
      detail = '已回复，状态正常';
    } else if (age > 30) {
      status = 'silent';
      detail = '超30天无互动';
    } else if (age > 14 && !lastCustMsg) {
      status = 'silent';
      detail = '无有效客户消息';
    } else if (!knownCids.has(c.cid) && age <= 14) {
      status = 'new_unknown';
      detail = '新客户待分析';
    } else {
      status = 'silent';
      detail = '低活跃';
    }

    classified[status].push({
      name: c.name,
      country: c.complianceCountryCode || c.country || '?',
      unread: c.unreadCount,
      age: age.toFixed(1) + 'd',
      isNew: !knownCids.has(c.cid),
      lastCustContent: (lastCustMsg?.content || '').slice(0, 80),
      lastMyContent: (lastHumanReply?.content || (lastSysReply ? '⚠️系统:' + lastSysReply.content.slice(0,40) : '')).slice(0, 80),
      detail,
    });
  }

  // ====== Step 9: 输出 ======
  const labels = {
    unread_no_reply: '未读未回',
    unread_replied: '未读已回',
    read_no_reply: '已读未回',
    read_replied: '已读已回（活跃）',
    new_unknown: '新客户待分析',
    silent: '沉默/低活跃',
  };

  for (const [key, label] of Object.entries(labels)) {
    const items = classified[key];
    if (items.length === 0) continue;

    // 排序：未读的按未读数倒序，其他的按时间倒序
    items.sort((a, b) => {
      if (key.startsWith('unread')) return b.unread - a.unread;
      return parseFloat(b.age) - parseFloat(a.age);
    });

    console.log(`## ${label} (${items.length}人)`);
    for (const it of items.slice(0, 25)) {
      const parts = [];
      if (it.unread > 0) parts.push(`${it.unread}条未读`);
      parts.push(it.age + '前');
      if (it.isNew) parts.push('🆕');
      const prefix = parts.join(' | ');

      const custPreview = it.lastCustContent ? ' ←客:' + it.lastCustContent : '';
      const myPreview = it.lastMyContent ? ' →我:' + it.lastMyContent : '';

      console.log(`  ${it.name} | ${it.country} | ${prefix}`);
      if (custPreview) console.log(`    ${custPreview}`);
      if (myPreview) console.log(`    ${myPreview}`);
    }
    if (items.length > 25) console.log(`  ... 共${items.length}人`);
    console.log('');
  }

  // ====== Step 10: 保存分类结果 + 更新已知客户 ======
  const result = {
    exportedAt: new Date().toISOString(),
    totalConversations: fullMeta.length,
    classified,
  };
  fs.writeFileSync(path.join(DATA_DIR, 'classification_latest.json'), JSON.stringify(result, null, 2));
  log('分类结果已保存: classification_latest.json');

  // 更新已知客户
  const allCids = fullMeta.map(c => c.cid);
  fs.writeFileSync(KNOWN_PATH, JSON.stringify({ updatedAt: new Date().toISOString(), cids: allCids }, null, 2));
  log(`已知客户基准已更新: ${allCids.length} 个`);

  // ====== 清理旧的 chat_history (保留最近) ======
  // 不清理，保持完整历史

  const elapsed = ((Date.now() - startTime) / 1000).toFixed(0);
  log(`全部完成，耗时 ${elapsed}s`);

  await browser.close();
}

