61	async function sendToTarget(cdpClient, sessionId, id, expression, awaitPromise) {
62	  return new Promise((resolve) => {
63	    const timeout = setTimeout(() => resolve(null), 35000);
64	    const handler = (msg) => {
65	      if (sessionId && msg.sessionId !== sessionId) return;
66	      try {
67	        const m = JSON.parse(msg.message);
68	        if (m.id === id) {
69	          clearTimeout(timeout);
70	          cdpClient.off('Target.receivedMessageFromTarget', handler);
71	          if (m.result?.result?.value !== null && m.result?.result?.value !== undefined) {
72	            resolve(m.result.result.value);
73	          } else {
74	            resolve(m.result);
75	          }
76	        }
77	      } catch (e) { clearTimeout(timeout); resolve(null); }
78	    };
79	    cdpClient.on('Target.receivedMessageFromTarget', handler);
80	    cdpClient.send('Target.sendMessageToTarget', {
81	      sessionId: sessionId,
82	      message: JSON.stringify({
83	        id, method: 'Runtime.evaluate',
84	        params: { expression, awaitPromise: !!awaitPromise, returnByValue: true }
85	      })
86	    }).catch(() => { clearTimeout(timeout); resolve(null); });
87	  });
88	}
89	
90	async function evalInIframe(cdpClient, sessionId, id, expression, awaitPromise) {
91	  const raw = await sendToTarget(cdpClient, sessionId, id, expression, awaitPromise);
92	  if (!raw) return null;
93	  try { return JSON.parse(raw); } catch (e) { return raw; }
94	}
